SELECT bmi
FROM health_metrics_history
WHERE bmi > 30;

SELECT group_name, group_description
FROM patient_groups
ORDER BY group_name ASC;

SELECT group_name
FROM patient_groups
WHERE group_id = 1;

SELECT patient_id, bmi
FROM health_metrics_history
ORDER BY bmi DESC;

SELECT group_name
FROM patient_groups
ORDER BY group_name ASC;
